//creds to IQ for his algorithm
float3 distort(in float2 p, in float t){
	t *= 2.0;
	p += 0.5*sin(t*float2(1.1,1.1)+float2(0.0,0.5));
	float a = atan2(p.x, p.y);
	float r = length(p);	
	float s = r*(1.0+0.5*cos(t*1.7));
	float2 uv = 0.1*t+0.05*p.yx+0.05*float2(cos(t+a*2.0),sin(t+a*2.0))/s;
	return iChannel0.Sample(iSampler0, 0.5*uv).rgb;
}
